import { G } from '../theme';
import React, { useState, useEffect, useCallback } from 'react';
import {
  Container, Typography, Box, Card, CardContent, TextField,
  Button, Chip, Divider, List, ListItem,
  Tab, Tabs, Alert, IconButton, LinearProgress, InputAdornment,
  CircularProgress, Accordion, AccordionSummary, AccordionDetails
} from '@mui/material';
import AddIcon from '@mui/icons-material/Add';
import DeleteIcon from '@mui/icons-material/Delete';
import TrendingUpIcon from '@mui/icons-material/TrendingUp';
import TrendingDownIcon from '@mui/icons-material/TrendingDown';
import AccountBalanceIcon from '@mui/icons-material/AccountBalance';
import LockIcon from '@mui/icons-material/Lock';
import ShieldIcon from '@mui/icons-material/Shield';
import SmartToyIcon from '@mui/icons-material/SmartToy';
import ExpandMoreIcon from '@mui/icons-material/ExpandMore';
import SavingsIcon from '@mui/icons-material/Savings';
import WarningIcon from '@mui/icons-material/Warning';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import { useAuth } from '../context/AuthContext';
import CryptoJS from 'crypto-js';

/* ─────────────────────────────────────────────────────────────
   AES-256 ENCRYPTION — all financial data encrypted at rest
───────────────────────────────────────────────────────────── */
const STORAGE_KEY = 'swpg_financial_v2';

function getEncKey(pin, username) {
  // Derive a strong key from PIN + username using SHA-256
  return CryptoJS.SHA256(`${username}:${pin}:swpg-financial-2024`).toString();
}

function saveEncrypted(data, key) {
  const str = JSON.stringify(data);
  const encrypted = CryptoJS.AES.encrypt(str, key).toString();
  localStorage.setItem(STORAGE_KEY, encrypted);
}

function loadDecrypted(key) {
  try {
    const encrypted = localStorage.getItem(STORAGE_KEY);
    if (!encrypted) return null;
    const bytes = CryptoJS.AES.decrypt(encrypted, key);
    const str = bytes.toString(CryptoJS.enc.Utf8);
    if (!str) return null;
    return JSON.parse(str);
  } catch {
    return null;
  }
}

/* ─────────────────────────────────────────────────────────────
   PIN LOCK
───────────────────────────────────────────────────────────── */
function PinLock({ onUnlock }) {
  const { user } = useAuth();
  const [pin, setPin] = useState('');
  const [error, setError] = useState('');
  const [shake, setShake] = useState(false);
  const [attempts, setAttempts] = useState(0);
  const [locked, setLocked] = useState(false);
  const [lockTimer, setLockTimer] = useState(0);

  useEffect(() => {
    if (locked && lockTimer > 0) {
      const t = setTimeout(() => setLockTimer(s => s - 1), 1000);
      return () => clearTimeout(t);
    }
    if (locked && lockTimer === 0) setLocked(false);
  }, [locked, lockTimer]);

  const addDigit = (d) => {
    if (locked || pin.length >= 4) return;
    const next = pin + d;
    setPin(next);
    setError('');
    if (next.length === 4) {
      setTimeout(() => {
        if (next === user?.pin) {
          onUnlock(next);
        } else {
          setShake(true);
          setTimeout(() => setShake(false), 600);
          const na = attempts + 1;
          setAttempts(na);
          if (na >= 3) { setLocked(true); setLockTimer(30); setError('Too many attempts. Locked for 30s.'); }
          else setError(`Wrong PIN. ${3 - na} attempt${3 - na === 1 ? '' : 's'} left.`);
          setPin('');
        }
      }, 120);
    }
  };

  return (
    <Box sx={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      <Box sx={{
        p: 5, borderRadius: 5, textAlign: 'center', maxWidth: 340, width: '100%', mx: 3,
        bgcolor: 'rgba(13,38,24,0.85)', backdropFilter: 'blur(24px)',
        border: '1px solid rgba(148,204,171,0.15)', boxShadow: '0 24px 60px rgba(0,0,0,0.5)',
        animation: shake ? 'shake 0.5s ease' : 'none',
        '@keyframes shake': { '0%,100%': { transform: 'translateX(0)' }, '20%': { transform: 'translateX(-10px)' }, '40%': { transform: 'translateX(10px)' }, '60%': { transform: 'translateX(-8px)' }, '80%': { transform: 'translateX(8px)' } }
      }}>
        <Box sx={{ width: 64, height: 64, borderRadius: 3, mx: 'auto', mb: 2.5, background: `linear-gradient(135deg, ${G.fern} 0%, ${G.forest} 100%)`, display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: `0 0 30px rgba(71,133,89,0.4)`, border: '1px solid rgba(148,204,171,0.2)' }}>
          {locked ? <ShieldIcon sx={{ color: '#f87171', fontSize: 30 }} /> : <LockIcon sx={{ color: G.mint, fontSize: 30 }} />}
        </Box>
        <Typography variant="h5" fontWeight={800} sx={{ color: G.foam, mb: 0.5 }}>Financial</Typography>
        <Typography sx={{ color: G.sage, fontSize: '0.85rem', mb: 3.5 }}>
          {locked ? `Locked — try again in ${lockTimer}s` : 'Enter your 4-digit PIN'}
        </Typography>
        <Box sx={{ display: 'flex', justifyContent: 'center', gap: 2, mb: 3 }}>
          {[0,1,2,3].map(i => (
            <Box key={i} sx={{ width: 18, height: 18, borderRadius: '50%', border: `2px solid ${pin.length > i ? G.mint : 'rgba(148,204,171,0.3)'}`, bgcolor: pin.length > i ? G.mint : 'transparent', transition: 'all 0.15s', boxShadow: pin.length > i ? `0 0 8px ${G.mint}` : 'none' }} />
          ))}
        </Box>
        {error && <Alert severity="error" sx={{ mb: 2.5, bgcolor: 'rgba(100,20,20,0.5)', color: '#f87171', border: '1px solid rgba(248,113,113,0.25)', fontSize: '0.82rem', py: 0.5 }}>{error}</Alert>}
        <Box sx={{ display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 1.2 }}>
          {[1,2,3,4,5,6,7,8,9,'',0,'⌫'].map((k, i) => (
            <Box key={i} onClick={() => { if (k === '') return; if (k === '⌫') setPin(p => p.slice(0,-1)); else addDigit(String(k)); }}
              sx={{ py: 1.8, borderRadius: 2.5, textAlign: 'center', cursor: k === '' || locked ? 'default' : 'pointer', bgcolor: k === '' ? 'transparent' : 'rgba(71,133,89,0.1)', border: `1px solid ${k === '' ? 'transparent' : 'rgba(148,204,171,0.15)'}`, color: k === '⌫' ? G.sage : G.foam, fontWeight: 700, fontSize: '1.2rem', opacity: locked && k !== '' ? 0.4 : 1, transition: 'all 0.15s', '&:hover': k !== '' && !locked ? { bgcolor: 'rgba(71,133,89,0.25)', borderColor: 'rgba(148,204,171,0.35)', transform: 'scale(1.05)' } : {}, userSelect: 'none' }}>{k}</Box>
          ))}
        </Box>
      </Box>
    </Box>
  );
}

/* ─────────────────────────────────────────────────────────────
   CATEGORIES
───────────────────────────────────────────────────────────── */
const CATEGORIES = {
  income: ['Salary', 'Freelance', 'Business', 'Investment Returns', 'Gift', 'Refund', 'Other Income'],
  expense: ['Rent/Housing', 'Food & Groceries', 'Transport', 'Utilities', 'Entertainment', 'Health/Medical', 'Clothing', 'Education', 'Subscriptions', 'Personal Care', 'Dining Out', 'Travel', 'Debt Payment', 'Other Expense'],
};

const CATEGORY_ICONS = {
  'Salary': '💼', 'Freelance': '💻', 'Business': '🏢', 'Investment Returns': '📈', 'Gift': '🎁', 'Refund': '↩️', 'Other Income': '💵',
  'Rent/Housing': '🏠', 'Food & Groceries': '🛒', 'Transport': '🚗', 'Utilities': '💡', 'Entertainment': '🎬',
  'Health/Medical': '🏥', 'Clothing': '👕', 'Education': '📚', 'Subscriptions': '📱', 'Personal Care': '🪥',
  'Dining Out': '🍽️', 'Travel': '✈️', 'Debt Payment': '💳', 'Other Expense': '📦',
};

/* ─────────────────────────────────────────────────────────────
   AI ANALYZER
───────────────────────────────────────────────────────────── */
function AIAnalyzer({ transactions, budgets }) {
  const [analysis, setAnalysis] = useState(null);
  const [loading, setLoading] = useState(false);

  const analyze = useCallback(() => {
    setLoading(true);
    setTimeout(() => {
      const income = transactions.filter(t => t.type === 'income').reduce((s, t) => s + t.amount, 0);
      const expense = transactions.filter(t => t.type === 'expense').reduce((s, t) => s + t.amount, 0);
      const balance = income - expense;
      const savingsRate = income > 0 ? ((balance / income) * 100) : 0;

      // Group by category
      const byCategory = {};
      transactions.filter(t => t.type === 'expense').forEach(t => {
        byCategory[t.category] = (byCategory[t.category] || 0) + t.amount;
      });

      // Top spending category
      const topCategory = Object.entries(byCategory).sort((a, b) => b[1] - a[1])[0];

      // Budget overspends
      const overspent = Object.entries(budgets).filter(([cat, limit]) => (byCategory[cat] || 0) > limit);

      // Monthly breakdown (last 3 months)
      const monthlyData = {};
      transactions.forEach(t => {
        const month = t.date.slice(0, 7);
        if (!monthlyData[month]) monthlyData[month] = { income: 0, expense: 0 };
        monthlyData[month][t.type] += t.amount;
      });

      // Trends
      const months = Object.keys(monthlyData).sort();
      const latestMonth = months[months.length - 1];
      const prevMonth = months[months.length - 2];
      const spendingTrend = latestMonth && prevMonth
        ? monthlyData[latestMonth].expense - monthlyData[prevMonth].expense
        : 0;

      // 50/30/20 rule check
      const needs = (byCategory['Rent/Housing'] || 0) + (byCategory['Food & Groceries'] || 0) + (byCategory['Utilities'] || 0) + (byCategory['Health/Medical'] || 0) + (byCategory['Transport'] || 0);
      const wants = expense - needs;
      const needsPct = income > 0 ? (needs / income) * 100 : 0;
      const wantsPct = income > 0 ? (wants / income) * 100 : 0;

      // Recommendations
      const recommendations = [];
      if (savingsRate < 20) recommendations.push({ icon: '⚠️', type: 'warning', text: `Your savings rate is ${savingsRate.toFixed(1)}% — below the recommended 20%. Try to cut ${Math.abs(income * 0.2 - balance).toFixed(0)} more per month.` });
      else recommendations.push({ icon: '✅', type: 'success', text: `Great savings rate of ${savingsRate.toFixed(1)}%! You're above the 20% target.` });

      if (topCategory) recommendations.push({ icon: '📊', type: 'info', text: `Your biggest expense is ${topCategory[0]} at $${topCategory[1].toFixed(2)} (${income > 0 ? ((topCategory[1]/income)*100).toFixed(1) : 0}% of income).` });

      if (spendingTrend > 0) recommendations.push({ icon: '📈', type: 'warning', text: `Spending increased by $${spendingTrend.toFixed(2)} compared to last month. Watch your ${topCategory?.[0] || 'expenses'}.` });
      else if (spendingTrend < 0) recommendations.push({ icon: '📉', type: 'success', text: `Great! You spent $${Math.abs(spendingTrend).toFixed(2)} less than last month.` });

      overspent.forEach(([cat, limit]) => {
        recommendations.push({ icon: '🚨', type: 'error', text: `Over budget on ${cat}: spent $${byCategory[cat].toFixed(2)} vs $${limit} limit (${(((byCategory[cat]-limit)/limit)*100).toFixed(0)}% over).` });
      });

      if (needsPct > 50) recommendations.push({ icon: '🏠', type: 'warning', text: `Needs (housing, food, utilities) take up ${needsPct.toFixed(1)}% of income — above the 50% guideline.` });
      if (wantsPct > 30) recommendations.push({ icon: '🎬', type: 'warning', text: `Wants (entertainment, dining, subscriptions) are ${wantsPct.toFixed(1)}% of income — above the 30% guideline.` });

      if (balance > 0) {
        const yearlyProjection = balance * 12;
        recommendations.push({ icon: '🔮', type: 'success', text: `At this rate you'll save $${yearlyProjection.toLocaleString()} this year. Invest it and it becomes ~$${(yearlyProjection * 1.07).toFixed(0)} in a year at 7% returns.` });
      }

      // Score
      let score = 50;
      if (savingsRate >= 20) score += 20;
      else if (savingsRate >= 10) score += 10;
      if (overspent.length === 0) score += 15;
      else score -= overspent.length * 5;
      if (spendingTrend < 0) score += 10;
      if (needsPct <= 50) score += 5;
      score = Math.max(0, Math.min(100, score));

      setAnalysis({ income, expense, balance, savingsRate, byCategory, overspent, monthlyData, months, recommendations, score, needsPct, wantsPct, topCategory });
      setLoading(false);
    }, 800);
  }, [transactions, budgets]);

  useEffect(() => { if (transactions.length > 0) analyze(); }, []);

  const scoreColor = analysis?.score >= 75 ? G.mid : analysis?.score >= 50 ? '#f59e0b' : '#ef4444';
  const scoreLabel = analysis?.score >= 75 ? 'Excellent' : analysis?.score >= 50 ? 'Good' : 'Needs Work';

  return (
    <Box>
      <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 3 }}>
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5 }}>
          <SmartToyIcon sx={{ color: G.mint, fontSize: 28 }} />
          <Box>
            <Typography variant="h6" fontWeight={800} sx={{ color: G.foam }}>AI Financial Analyst</Typography>
            <Typography sx={{ color: G.sage, fontSize: '0.78rem' }}>Deep analysis of your money</Typography>
          </Box>
        </Box>
        <Button onClick={analyze} variant="outlined" size="small" startIcon={loading ? <CircularProgress size={14} sx={{ color: G.mint }} /> : <SmartToyIcon />}
          sx={{ borderColor: 'rgba(148,204,171,0.3)', color: G.mint, fontWeight: 700, '&:hover': { borderColor: G.mint } }}>
          {loading ? 'Analyzing...' : 'Re-analyze'}
        </Button>
      </Box>

      {loading && !analysis && (
        <Box sx={{ textAlign: 'center', py: 6 }}>
          <CircularProgress sx={{ color: G.mint }} />
          <Typography sx={{ color: G.sage, mt: 2 }}>Analyzing your finances...</Typography>
        </Box>
      )}

      {analysis && (
        <Box sx={{ display: 'flex', flexDirection: 'column', gap: 3 }}>

          {/* Financial Health Score */}
          <Card sx={{ background: `linear-gradient(135deg, rgba(13,38,24,0.9), rgba(29,61,40,0.8))`, border: `1px solid ${scoreColor}40` }}>
            <CardContent sx={{ p: 3 }}>
              <Typography sx={{ color: G.sage, fontSize: '0.78rem', letterSpacing: 2, textTransform: 'uppercase', mb: 2 }}>Financial Health Score</Typography>
              <Box sx={{ display: 'flex', alignItems: 'center', gap: 3 }}>
                <Box sx={{ position: 'relative', width: 80, height: 80 }}>
                  <CircularProgress variant="determinate" value={100} size={80} sx={{ color: 'rgba(148,204,171,0.1)', position: 'absolute' }} />
                  <CircularProgress variant="determinate" value={analysis.score} size={80} sx={{ color: scoreColor }} />
                  <Box sx={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', flexDirection: 'column' }}>
                    <Typography sx={{ fontWeight: 900, fontSize: '1.2rem', color: scoreColor, lineHeight: 1 }}>{analysis.score}</Typography>
                    <Typography sx={{ fontSize: '0.6rem', color: G.sage }}>/ 100</Typography>
                  </Box>
                </Box>
                <Box sx={{ flex: 1 }}>
                  <Typography sx={{ fontWeight: 800, fontSize: '1.4rem', color: scoreColor }}>{scoreLabel}</Typography>
                  <Typography sx={{ color: G.sage, fontSize: '0.85rem', mt: 0.5 }}>
                    Based on savings rate, budget compliance, spending trends & 50/30/20 rule
                  </Typography>
                  <LinearProgress variant="determinate" value={analysis.score} sx={{ mt: 1.5, height: 6, borderRadius: 3, bgcolor: 'rgba(148,204,171,0.1)', '& .MuiLinearProgress-bar': { bgcolor: scoreColor, borderRadius: 3 } }} />
                </Box>
              </Box>
            </CardContent>
          </Card>

          {/* Key Metrics */}
          <Box sx={{ display: 'grid', gridTemplateColumns: { xs: '1fr 1fr', md: 'repeat(4,1fr)' }, gap: 2 }}>
            {[
              { label: 'Total Income', value: `$${analysis.income.toLocaleString()}`, sub: 'All sources', color: G.mid, icon: '💰' },
              { label: 'Total Expenses', value: `$${analysis.expense.toLocaleString()}`, sub: `${Object.keys(analysis.byCategory).length} categories`, color: '#ef4444', icon: '💸' },
              { label: 'Net Balance', value: `${analysis.balance >= 0 ? '+' : ''}$${analysis.balance.toLocaleString()}`, sub: analysis.balance >= 0 ? 'Surplus 🎉' : 'Deficit ⚠️', color: analysis.balance >= 0 ? G.mid : '#ef4444', icon: '⚖️' },
              { label: 'Savings Rate', value: `${analysis.savingsRate.toFixed(1)}%`, sub: analysis.savingsRate >= 20 ? 'Above target ✅' : 'Below 20% target', color: analysis.savingsRate >= 20 ? G.mid : '#f59e0b', icon: '📊' },
            ].map(m => (
              <Box key={m.label} sx={{ p: 2.5, borderRadius: 3, bgcolor: 'rgba(13,38,24,0.7)', border: `1px solid rgba(148,204,171,0.1)` }}>
                <Typography sx={{ fontSize: '1.4rem', mb: 0.5 }}>{m.icon}</Typography>
                <Typography sx={{ fontSize: '0.7rem', color: G.sage, letterSpacing: 1, textTransform: 'uppercase' }}>{m.label}</Typography>
                <Typography sx={{ fontWeight: 800, fontSize: '1.3rem', color: m.color, my: 0.3 }}>{m.value}</Typography>
                <Typography sx={{ fontSize: '0.72rem', color: 'rgba(232,245,238,0.4)' }}>{m.sub}</Typography>
              </Box>
            ))}
          </Box>

          {/* 50/30/20 Rule */}
          <Card sx={{ bgcolor: 'rgba(13,38,24,0.7)', border: '1px solid rgba(148,204,171,0.1)' }}>
            <CardContent sx={{ p: 3 }}>
              <Typography sx={{ color: G.foam, fontWeight: 700, mb: 2 }}>📐 50/30/20 Rule Analysis</Typography>
              {[
                { label: 'Needs (50% target)', pct: analysis.needsPct, target: 50, color: '#60a5fa', desc: 'Housing, food, utilities, transport, health' },
                { label: 'Wants (30% target)', pct: analysis.wantsPct, target: 30, color: '#f59e0b', desc: 'Entertainment, dining out, subscriptions' },
                { label: 'Savings (20% target)', pct: analysis.savingsRate, target: 20, color: G.mid, desc: 'Everything left after needs & wants' },
              ].map(r => (
                <Box key={r.label} sx={{ mb: 2 }}>
                  <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 0.5 }}>
                    <Typography sx={{ color: G.sage, fontSize: '0.82rem' }}>{r.label}</Typography>
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                      <Typography sx={{ color: r.pct > r.target ? '#f87171' : r.color, fontWeight: 700, fontSize: '0.85rem' }}>
                        {r.pct.toFixed(1)}%
                      </Typography>
                      {r.pct > r.target
                        ? <WarningIcon sx={{ fontSize: 14, color: '#f87171' }} />
                        : <CheckCircleIcon sx={{ fontSize: 14, color: G.mid }} />}
                    </Box>
                  </Box>
                  <Box sx={{ position: 'relative' }}>
                    <LinearProgress variant="determinate" value={Math.min(r.pct, 100)} sx={{ height: 8, borderRadius: 4, bgcolor: 'rgba(148,204,171,0.08)', '& .MuiLinearProgress-bar': { bgcolor: r.pct > r.target ? '#ef4444' : r.color, borderRadius: 4 } }} />
                    {/* Target marker */}
                    <Box sx={{ position: 'absolute', top: 0, left: `${r.target}%`, width: 2, height: '100%', bgcolor: 'rgba(255,255,255,0.3)', borderRadius: 1 }} />
                  </Box>
                  <Typography sx={{ color: 'rgba(232,245,238,0.3)', fontSize: '0.7rem', mt: 0.3 }}>{r.desc}</Typography>
                </Box>
              ))}
            </CardContent>
          </Card>

          {/* Spending by Category */}
          <Card sx={{ bgcolor: 'rgba(13,38,24,0.7)', border: '1px solid rgba(148,204,171,0.1)' }}>
            <CardContent sx={{ p: 3 }}>
              <Typography sx={{ color: G.foam, fontWeight: 700, mb: 2 }}>🗂️ Spending Breakdown</Typography>
              {Object.entries(analysis.byCategory).sort((a, b) => b[1] - a[1]).map(([cat, amt]) => {
                const pct = analysis.income > 0 ? (amt / analysis.income) * 100 : 0;
                const overBudget = analysis.overspent.find(o => o[0] === cat);
                return (
                  <Box key={cat} sx={{ mb: 2 }}>
                    <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 0.5 }}>
                      <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                        <Typography sx={{ fontSize: '1rem' }}>{CATEGORY_ICONS[cat] || '📦'}</Typography>
                        <Typography sx={{ color: G.sage, fontSize: '0.83rem', fontWeight: 600 }}>{cat}</Typography>
                        {overBudget && <Chip label="Over budget" size="small" sx={{ bgcolor: 'rgba(239,68,68,0.2)', color: '#f87171', fontSize: '0.65rem', height: 18 }} />}
                      </Box>
                      <Box sx={{ textAlign: 'right' }}>
                        <Typography sx={{ color: overBudget ? '#f87171' : G.foam, fontWeight: 700, fontSize: '0.88rem' }}>${amt.toFixed(2)}</Typography>
                        <Typography sx={{ color: 'rgba(232,245,238,0.35)', fontSize: '0.68rem' }}>{pct.toFixed(1)}% of income</Typography>
                      </Box>
                    </Box>
                    <LinearProgress variant="determinate" value={Math.min(pct * 2, 100)} sx={{ height: 5, borderRadius: 3, bgcolor: 'rgba(148,204,171,0.08)', '& .MuiLinearProgress-bar': { bgcolor: overBudget ? '#ef4444' : G.fern, borderRadius: 3 } }} />
                  </Box>
                );
              })}
              {Object.keys(analysis.byCategory).length === 0 && (
                <Typography sx={{ color: G.sage, textAlign: 'center', py: 2 }}>No expense transactions yet</Typography>
              )}
            </CardContent>
          </Card>

          {/* Monthly Trend */}
          {analysis.months.length > 1 && (
            <Card sx={{ bgcolor: 'rgba(13,38,24,0.7)', border: '1px solid rgba(148,204,171,0.1)' }}>
              <CardContent sx={{ p: 3 }}>
                <Typography sx={{ color: G.foam, fontWeight: 700, mb: 2 }}>📅 Monthly Trend</Typography>
                {analysis.months.map(m => {
                  const d = analysis.monthlyData[m];
                  const net = d.income - d.expense;
                  return (
                    <Box key={m} sx={{ mb: 2, p: 2, borderRadius: 2, bgcolor: 'rgba(71,133,89,0.06)', border: '1px solid rgba(148,204,171,0.08)' }}>
                      <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
                        <Typography sx={{ color: G.foam, fontWeight: 700, fontSize: '0.9rem' }}>{new Date(m + '-01').toLocaleString('default', { month: 'long', year: 'numeric' })}</Typography>
                        <Typography sx={{ color: net >= 0 ? G.mid : '#ef4444', fontWeight: 700 }}>{net >= 0 ? '+' : ''}${net.toFixed(2)}</Typography>
                      </Box>
                      <Box sx={{ display: 'flex', gap: 3 }}>
                        <Typography sx={{ color: G.mid, fontSize: '0.8rem' }}>↑ ${d.income.toFixed(2)}</Typography>
                        <Typography sx={{ color: '#ef4444', fontSize: '0.8rem' }}>↓ ${d.expense.toFixed(2)}</Typography>
                      </Box>
                    </Box>
                  );
                })}
              </CardContent>
            </Card>
          )}

          {/* Recommendations */}
          <Card sx={{ bgcolor: 'rgba(13,38,24,0.7)', border: '1px solid rgba(148,204,171,0.1)' }}>
            <CardContent sx={{ p: 3 }}>
              <Typography sx={{ color: G.foam, fontWeight: 700, mb: 2 }}>🤖 AI Recommendations</Typography>
              <Box sx={{ display: 'flex', flexDirection: 'column', gap: 1.5 }}>
                {analysis.recommendations.map((r, i) => (
                  <Box key={i} sx={{
                    p: 2, borderRadius: 2, display: 'flex', gap: 1.5, alignItems: 'flex-start',
                    bgcolor: r.type === 'error' ? 'rgba(239,68,68,0.08)' : r.type === 'warning' ? 'rgba(245,158,11,0.08)' : r.type === 'success' ? 'rgba(71,133,89,0.12)' : 'rgba(148,204,171,0.06)',
                    border: `1px solid ${r.type === 'error' ? 'rgba(239,68,68,0.2)' : r.type === 'warning' ? 'rgba(245,158,11,0.2)' : r.type === 'success' ? 'rgba(71,133,89,0.2)' : 'rgba(148,204,171,0.1)'}`,
                  }}>
                    <Typography sx={{ fontSize: '1.1rem', flexShrink: 0, mt: 0.1 }}>{r.icon}</Typography>
                    <Typography sx={{ color: G.foam, fontSize: '0.85rem', lineHeight: 1.5 }}>{r.text}</Typography>
                  </Box>
                ))}
              </Box>
            </CardContent>
          </Card>

          {/* Projection */}
          {analysis.balance > 0 && (
            <Card sx={{ background: `linear-gradient(135deg, rgba(13,38,24,0.9), rgba(45,106,79,0.3))`, border: `1px solid rgba(148,204,171,0.2)` }}>
              <CardContent sx={{ p: 3 }}>
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5, mb: 2 }}>
                  <SavingsIcon sx={{ color: G.mint, fontSize: 26 }} />
                  <Typography sx={{ color: G.foam, fontWeight: 700 }}>📈 Savings Projections</Typography>
                </Box>
                <Box sx={{ display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 2 }}>
                  {[
                    { label: '1 Year', value: analysis.balance * 12, note: 'No interest' },
                    { label: '1 Year (7% invested)', value: analysis.balance * 12 * 1.07, note: 'Index fund avg' },
                    { label: '5 Years (7% compound)', value: analysis.balance * 12 * ((Math.pow(1.07, 5) - 1) / 0.07), note: 'Compound interest' },
                  ].map(p => (
                    <Box key={p.label} sx={{ textAlign: 'center', p: 2, borderRadius: 2, bgcolor: 'rgba(13,38,24,0.5)', border: '1px solid rgba(148,204,171,0.1)' }}>
                      <Typography sx={{ color: G.sage, fontSize: '0.72rem', mb: 0.5 }}>{p.label}</Typography>
                      <Typography sx={{ color: G.mint, fontWeight: 800, fontSize: '1.1rem' }}>${Math.round(p.value).toLocaleString()}</Typography>
                      <Typography sx={{ color: 'rgba(232,245,238,0.3)', fontSize: '0.65rem', mt: 0.3 }}>{p.note}</Typography>
                    </Box>
                  ))}
                </Box>
              </CardContent>
            </Card>
          )}
        </Box>
      )}

      {!analysis && !loading && transactions.length === 0 && (
        <Box sx={{ textAlign: 'center', py: 6, color: G.sage }}>
          <SmartToyIcon sx={{ fontSize: 48, mb: 2, opacity: 0.4 }} />
          <Typography>Add some transactions first, then the AI will analyze your finances.</Typography>
        </Box>
      )}
    </Box>
  );
}

/* ─────────────────────────────────────────────────────────────
   MAIN FINANCIAL CONTENT
───────────────────────────────────────────────────────────── */
function FinancialContent({ pin, username }) {
  const encKey = getEncKey(pin, username);

  const [tab, setTab] = useState(0);
  const [transactions, setTransactions] = useState([]);
  const [budgets, setBudgets] = useState({
    'Rent/Housing': 1200, 'Food & Groceries': 400, 'Transport': 200,
    'Entertainment': 150, 'Subscriptions': 80, 'Dining Out': 120, 'Clothing': 100,
  });
  const [newTx, setNewTx] = useState({ type: 'expense', amount: '', category: '', note: '', date: new Date().toISOString().split('T')[0] });
  const [budgetEdit, setBudgetEdit] = useState({});
  const [newBudgetCat, setNewBudgetCat] = useState('');
  const [newBudgetAmt, setNewBudgetAmt] = useState('');

  // Load encrypted data on mount
  useEffect(() => {
    const saved = loadDecrypted(encKey);
    if (saved) {
      if (saved.transactions) setTransactions(saved.transactions);
      if (saved.budgets) setBudgets(saved.budgets);
    }
  }, [encKey]);

  // Auto-save encrypted on every change
  useEffect(() => {
    saveEncrypted({ transactions, budgets }, encKey);
  }, [transactions, budgets, encKey]);

  const totalIncome = transactions.filter(t => t.type === 'income').reduce((s, t) => s + t.amount, 0);
  const totalExpense = transactions.filter(t => t.type === 'expense').reduce((s, t) => s + t.amount, 0);
  const netBalance = totalIncome - totalExpense;
  const savingsRate = totalIncome > 0 ? Math.round(((totalIncome - totalExpense) / totalIncome) * 100) : 0;

  const addTransaction = () => {
    if (!newTx.amount || !newTx.category) return;
    setTransactions(prev => [...prev, { id: Date.now(), ...newTx, amount: parseFloat(newTx.amount) }]);
    setNewTx({ type: 'expense', amount: '', category: '', note: '', date: new Date().toISOString().split('T')[0] });
  };

  const deleteTransaction = (id) => setTransactions(prev => prev.filter(t => t.id !== id));

  const inputSx = {
    '& .MuiOutlinedInput-root': {
      bgcolor: 'rgba(13,38,24,0.6)', color: G.foam,
      '& fieldset': { borderColor: 'rgba(148,204,171,0.15)' },
      '&:hover fieldset': { borderColor: G.mint },
      '&.Mui-focused fieldset': { borderColor: G.mint, borderWidth: 2 },
    },
    '& .MuiInputLabel-root': { color: G.sage },
    '& .MuiInputLabel-root.Mui-focused': { color: G.mint },
    '& .MuiInputBase-input': { color: G.foam },
    '& .MuiSelect-icon': { color: G.sage },
  };

  return (
    <Container maxWidth="lg" sx={{ py: 4 }}>
      {/* Header */}
      <Box sx={{ mb: 4 }}>
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5, mb: 0.5 }}>
          <Typography variant="h4" fontWeight={800} sx={{ color: G.foam }}>💳 Financial</Typography>
          <Chip icon={<LockIcon sx={{ fontSize: '14px !important' }} />} label="AES-256 Encrypted" size="small"
            sx={{ bgcolor: 'rgba(71,133,89,0.15)', color: G.mint, border: '1px solid rgba(148,204,171,0.2)', fontSize: '0.7rem' }} />
        </Box>
        <Typography variant="body2" sx={{ color: G.sage }}>Track every dollar · All data encrypted on your device</Typography>
      </Box>

      {/* Summary Cards */}
      <Box sx={{ display: 'grid', gridTemplateColumns: { xs: '1fr 1fr', md: 'repeat(4,1fr)' }, gap: 2, mb: 4 }}>
        {[
          { label: 'Total Income', value: `$${totalIncome.toLocaleString()}`, color: G.mid, icon: <TrendingUpIcon /> },
          { label: 'Total Expenses', value: `$${totalExpense.toLocaleString()}`, color: '#ef4444', icon: <TrendingDownIcon /> },
          { label: 'Net Balance', value: `${netBalance >= 0 ? '+' : ''}$${netBalance.toLocaleString()}`, color: netBalance >= 0 ? G.mid : '#ef4444', icon: <AccountBalanceIcon /> },
          { label: 'Savings Rate', value: `${savingsRate}%`, color: savingsRate >= 20 ? G.mid : savingsRate >= 10 ? '#f59e0b' : '#ef4444', icon: <SavingsIcon /> },
        ].map(item => (
          <Box key={item.label} sx={{ p: 2.5, borderRadius: 3, bgcolor: 'rgba(13,38,24,0.7)', border: '1px solid rgba(148,204,171,0.1)' }}>
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 1, color: item.color }}>{item.icon}
              <Typography sx={{ color: G.sage, fontSize: '0.72rem', textTransform: 'uppercase', letterSpacing: 1 }}>{item.label}</Typography>
            </Box>
            <Typography sx={{ fontWeight: 800, fontSize: '1.4rem', color: item.color }}>{item.value}</Typography>
          </Box>
        ))}
      </Box>

      {/* Tabs */}
      <Tabs value={tab} onChange={(_, v) => setTab(v)} sx={{ mb: 3 }}>
        <Tab label="📊 AI Analyst" />
        <Tab label="+ Transactions" />
        <Tab label="📋 History" />
        <Tab label="🎯 Budgets" />
      </Tabs>

      {/* TAB 0 — AI Analyst */}
      {tab === 0 && <AIAnalyzer transactions={transactions} budgets={budgets} />}

      {/* TAB 1 — Add Transaction */}
      {tab === 1 && (
        <Card sx={{ bgcolor: 'rgba(13,38,24,0.7)', border: '1px solid rgba(148,204,171,0.1)', borderRadius: 3 }}>
          <CardContent sx={{ p: 3 }}>
            <Typography variant="h6" fontWeight={700} sx={{ color: G.foam, mb: 3 }}>Add Transaction</Typography>

            {/* Type toggle */}
            <Box sx={{ display: 'flex', gap: 1, mb: 3 }}>
              {['expense', 'income'].map(t => (
                <Box key={t} onClick={() => setNewTx(n => ({ ...n, type: t, category: '' }))}
                  sx={{ px: 3, py: 1, borderRadius: 99, cursor: 'pointer', fontWeight: 700, fontSize: '0.88rem',
                    bgcolor: newTx.type === t ? (t === 'income' ? 'rgba(71,133,89,0.3)' : 'rgba(239,68,68,0.2)') : 'rgba(148,204,171,0.06)',
                    color: newTx.type === t ? (t === 'income' ? G.mint : '#f87171') : G.sage,
                    border: `1px solid ${newTx.type === t ? (t === 'income' ? 'rgba(148,204,171,0.4)' : 'rgba(239,68,68,0.4)') : 'rgba(148,204,171,0.1)'}`,
                    transition: 'all 0.2s',
                  }}>
                  {t === 'income' ? '↑ Income' : '↓ Expense'}
                </Box>
              ))}
            </Box>

            <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2.5, maxWidth: 560 }}>
              <Box sx={{ display: 'flex', gap: 2 }}>
                <TextField label="Amount ($)" type="number" value={newTx.amount}
                  onChange={e => setNewTx(n => ({ ...n, amount: e.target.value }))}
                  InputProps={{ startAdornment: <InputAdornment position="start"><Typography sx={{ color: G.sage }}>$</Typography></InputAdornment> }}
                  sx={{ ...inputSx, width: 160 }} />
                <TextField label="Date" type="date" value={newTx.date}
                  onChange={e => setNewTx(n => ({ ...n, date: e.target.value }))}
                  InputLabelProps={{ shrink: true }} sx={{ ...inputSx, flex: 1 }} />
              </Box>

              <TextField select label="Category" value={newTx.category}
                onChange={e => setNewTx(n => ({ ...n, category: e.target.value }))}
                SelectProps={{ native: true }} sx={inputSx}>
                <option value="">Select category</option>
                {CATEGORIES[newTx.type].map(c => <option key={c} value={c}>{CATEGORY_ICONS[c] || ''} {c}</option>)}
              </TextField>

              <TextField label="Note (optional)" value={newTx.note}
                onChange={e => setNewTx(n => ({ ...n, note: e.target.value }))}
                placeholder="e.g. Monthly rent, Coffee, Uber..." sx={inputSx} />

              <Button variant="contained" onClick={addTransaction} startIcon={<AddIcon />}
                disabled={!newTx.amount || !newTx.category}
                sx={{ py: 1.5, fontWeight: 700, bgcolor: G.pine, '&:hover': { bgcolor: G.fern }, '&.Mui-disabled': { bgcolor: 'rgba(71,133,89,0.15)', color: G.sage } }}>
                Add {newTx.type === 'income' ? 'Income' : 'Expense'}
              </Button>
            </Box>

            <Alert severity="info" sx={{ mt: 3, bgcolor: 'rgba(13,38,24,0.8)', color: G.mint, border: '1px solid rgba(148,204,171,0.15)', '& .MuiAlert-icon': { color: G.mint } }}>
              🔐 All transactions are AES-256 encrypted with your PIN. Only you can read this data.
            </Alert>
          </CardContent>
        </Card>
      )}

      {/* TAB 2 — Transaction History */}
      {tab === 2 && (
        <Card sx={{ bgcolor: 'rgba(13,38,24,0.7)', border: '1px solid rgba(148,204,171,0.1)', borderRadius: 3 }}>
          <CardContent sx={{ p: 0 }}>
            <Box sx={{ p: 3, pb: 1, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <Typography variant="h6" fontWeight={700} sx={{ color: G.foam }}>
                Transaction History ({transactions.length})
              </Typography>
              {transactions.length > 0 && (
                <Button size="small" color="error" onClick={() => { if(window.confirm('Delete ALL transactions?')) setTransactions([]); }}
                  sx={{ color: '#f87171', fontSize: '0.75rem' }}>Clear All</Button>
              )}
            </Box>
            {transactions.length === 0 ? (
              <Box sx={{ textAlign: 'center', py: 6 }}>
                <Typography sx={{ color: G.sage }}>No transactions yet. Add your first one in the Transactions tab.</Typography>
              </Box>
            ) : (
              <List sx={{ p: 0 }}>
                {[...transactions].reverse().map((tx, i) => (
                  <React.Fragment key={tx.id}>
                    {i > 0 && <Divider sx={{ borderColor: 'rgba(148,204,171,0.06)' }} />}
                    <ListItem sx={{ px: 3, py: 1.5 }}
                      secondaryAction={
                        <IconButton onClick={() => deleteTransaction(tx.id)} size="small" sx={{ color: 'rgba(232,245,238,0.2)', '&:hover': { color: '#ef4444' } }}>
                          <DeleteIcon fontSize="small" />
                        </IconButton>
                      }>
                      <Box sx={{ display: 'flex', alignItems: 'center', gap: 2, flex: 1 }}>
                        <Box sx={{ width: 40, height: 40, borderRadius: 2, bgcolor: tx.type === 'income' ? 'rgba(71,133,89,0.15)' : 'rgba(239,68,68,0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1.1rem', flexShrink: 0 }}>
                          {CATEGORY_ICONS[tx.category] || (tx.type === 'income' ? '💵' : '💸')}
                        </Box>
                        <Box sx={{ flex: 1, minWidth: 0 }}>
                          <Typography fontWeight={600} sx={{ color: G.foam, fontSize: '0.9rem' }}>{tx.category}</Typography>
                          <Typography variant="caption" sx={{ color: G.sage }}>{tx.note || '—'} · {tx.date}</Typography>
                        </Box>
                        <Typography fontWeight={800} sx={{ color: tx.type === 'income' ? G.mid : '#ef4444', fontSize: '0.95rem', mr: 4, flexShrink: 0 }}>
                          {tx.type === 'income' ? '+' : '-'}${tx.amount.toFixed(2)}
                        </Typography>
                      </Box>
                    </ListItem>
                  </React.Fragment>
                ))}
              </List>
            )}
          </CardContent>
        </Card>
      )}

      {/* TAB 3 — Budgets */}
      {tab === 3 && (
        <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
          <Typography variant="h6" fontWeight={700} sx={{ color: G.foam }}>🎯 Monthly Budgets</Typography>

          {Object.entries(budgets).map(([cat, limit]) => {
            const spent = transactions.filter(t => t.type === 'expense' && t.category === cat).reduce((s, t) => s + t.amount, 0);
            const pct = limit > 0 ? Math.min((spent / limit) * 100, 100) : 0;
            const over = spent > limit;
            return (
              <Card key={cat} sx={{ bgcolor: 'rgba(13,38,24,0.7)', border: `1px solid ${over ? 'rgba(239,68,68,0.2)' : 'rgba(148,204,171,0.1)'}`, borderRadius: 3 }}>
                <CardContent sx={{ p: 2.5 }}>
                  <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1 }}>
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                      <Typography sx={{ fontSize: '1.1rem' }}>{CATEGORY_ICONS[cat] || '📦'}</Typography>
                      <Typography fontWeight={700} sx={{ color: G.foam }}>{cat}</Typography>
                      {over && <Chip label="Over!" size="small" sx={{ bgcolor: 'rgba(239,68,68,0.2)', color: '#f87171', fontSize: '0.65rem', height: 20 }} />}
                    </Box>
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                      {budgetEdit[cat] !== undefined ? (
                        <>
                          <TextField size="small" type="number" value={budgetEdit[cat]}
                            onChange={e => setBudgetEdit(b => ({ ...b, [cat]: e.target.value }))}
                            sx={{ width: 100, ...inputSx }} InputProps={{ startAdornment: <InputAdornment position="start"><Typography sx={{ color: G.sage, fontSize: '0.85rem' }}>$</Typography></InputAdornment> }} />
                          <Button size="small" onClick={() => { setBudgets(b => ({ ...b, [cat]: parseFloat(budgetEdit[cat]) || limit })); setBudgetEdit(b => { const n = { ...b }; delete n[cat]; return n; }); }}
                            sx={{ color: G.mint, minWidth: 0, px: 1 }}>✓</Button>
                        </>
                      ) : (
                        <>
                          <Typography sx={{ color: over ? '#f87171' : G.sage, fontSize: '0.85rem' }}>${spent.toFixed(0)} / ${limit}</Typography>
                          <IconButton size="small" onClick={() => setBudgetEdit(b => ({ ...b, [cat]: limit }))} sx={{ color: G.sage, p: 0.4 }}>
                            <Typography sx={{ fontSize: '0.7rem' }}>✏️</Typography>
                          </IconButton>
                          <IconButton size="small" onClick={() => setBudgets(b => { const n = { ...b }; delete n[cat]; return n; })} sx={{ color: 'rgba(239,68,68,0.5)', p: 0.4, '&:hover': { color: '#ef4444' } }}>
                            <DeleteIcon sx={{ fontSize: 14 }} />
                          </IconButton>
                        </>
                      )}
                    </Box>
                  </Box>
                  <LinearProgress variant="determinate" value={pct}
                    sx={{ height: 6, borderRadius: 3, bgcolor: 'rgba(148,204,171,0.08)', '& .MuiLinearProgress-bar': { bgcolor: over ? '#ef4444' : pct > 75 ? '#f59e0b' : G.fern, borderRadius: 3 } }} />
                  <Typography sx={{ color: 'rgba(232,245,238,0.3)', fontSize: '0.72rem', mt: 0.5 }}>
                    {over ? `$${(spent - limit).toFixed(2)} over budget` : `$${(limit - spent).toFixed(2)} remaining`}
                  </Typography>
                </CardContent>
              </Card>
            );
          })}

          {/* Add new budget */}
          <Card sx={{ bgcolor: 'rgba(13,38,24,0.7)', border: '1px solid rgba(148,204,171,0.1)', borderRadius: 3 }}>
            <CardContent sx={{ p: 2.5 }}>
              <Typography fontWeight={700} sx={{ color: G.foam, mb: 2 }}>+ Add Budget</Typography>
              <Box sx={{ display: 'flex', gap: 2, flexWrap: 'wrap' }}>
                <TextField select label="Category" value={newBudgetCat} onChange={e => setNewBudgetCat(e.target.value)}
                  SelectProps={{ native: true }} sx={{ ...inputSx, minWidth: 200 }}>
                  <option value="">Select category</option>
                  {CATEGORIES.expense.filter(c => !budgets[c]).map(c => <option key={c} value={c}>{c}</option>)}
                </TextField>
                <TextField label="Monthly limit ($)" type="number" value={newBudgetAmt}
                  onChange={e => setNewBudgetAmt(e.target.value)}
                  sx={{ ...inputSx, width: 160 }}
                  InputProps={{ startAdornment: <InputAdornment position="start"><Typography sx={{ color: G.sage }}>$</Typography></InputAdornment> }} />
                <Button variant="contained" startIcon={<AddIcon />}
                  disabled={!newBudgetCat || !newBudgetAmt}
                  onClick={() => { setBudgets(b => ({ ...b, [newBudgetCat]: parseFloat(newBudgetAmt) })); setNewBudgetCat(''); setNewBudgetAmt(''); }}
                  sx={{ bgcolor: G.pine, '&:hover': { bgcolor: G.fern }, alignSelf: 'center' }}>
                  Add Budget
                </Button>
              </Box>
            </CardContent>
          </Card>
        </Box>
      )}
    </Container>
  );
}

/* ─────────────────────────────────────────────────────────────
   ENTRY POINT
───────────────────────────────────────────────────────────── */
export default function Financial() {
  const { user } = useAuth();
  const [unlocked, setUnlocked] = useState(false);
  const [pin, setPin] = useState('');

  if (!unlocked) return <PinLock onUnlock={(p) => { setPin(p); setUnlocked(true); }} />;
  return <FinancialContent pin={pin} username={user?.username || 'user'} />;
}
